import { describe, it, expect } from 'vitest'
import { readFile } from 'node:fs/promises'
import { join } from 'node:path'
import { computeHash, verifyPdf } from './pdf-verifier.js'

// Path to the known-good PAdES reference PDF generated by CORTEX
const REFERENCE_PDF = join(
  process.env.HOME || '',
  'Attestto/CORTEX/api/tmp/pades-reference_digitally_signed.pdf'
)

describe('pdf-verifier', () => {
  describe('computeHash', () => {
    it('computes SHA-256 of known input', async () => {
      const encoder = new TextEncoder()
      const buffer = encoder.encode('hello world').buffer
      const hash = await computeHash(buffer)
      // SHA-256 of "hello world"
      expect(hash).toBe('b94d27b9934d3e08a52e52d7da7dabfac484efe37a5380ee9088f7ace2efcde9')
    })

    it('produces different hashes for different input', async () => {
      const encoder = new TextEncoder()
      const hash1 = await computeHash(encoder.encode('file1').buffer)
      const hash2 = await computeHash(encoder.encode('file2').buffer)
      expect(hash1).not.toBe(hash2)
    })
  })

  describe('extractSignaturesFromBytes — known-good PAdES reference', () => {
    it('detects the PKCS#7 digital signature', async () => {
      const bytes = await readFile(REFERENCE_PDF)
      const blob = new Blob([bytes], { type: 'application/pdf' })
      const file = new File([blob], 'pades-reference_digitally_signed.pdf')

      const result = await verifyPdf(file)

      expect(result.isPdf).toBe(true)
      expect(result.hash).toBeTruthy()
      expect(result.hash).toHaveLength(64) // SHA-256 hex
      expect(result.signatures.length).toBeGreaterThanOrEqual(1)
    })

    it('extracts signer name', async () => {
      const bytes = await readFile(REFERENCE_PDF)
      const file = new File([bytes], 'pades-reference_digitally_signed.pdf')

      const result = await verifyPdf(file)

      const sig = result.signatures[0]
      expect(sig).toBeDefined()
      expect(sig.name).toBe('EDUARDO ANTONIO CHONGKAN LIOS')
    })

    it('extracts reason', async () => {
      const bytes = await readFile(REFERENCE_PDF)
      const file = new File([bytes], 'pades-reference_digitally_signed.pdf')

      const result = await verifyPdf(file)

      const sig = result.signatures[0]
      expect(sig.reason).toContain('PAdES reference')
    })

    it('extracts location', async () => {
      const bytes = await readFile(REFERENCE_PDF)
      const file = new File([bytes], 'pades-reference_digitally_signed.pdf')

      const result = await verifyPdf(file)

      const sig = result.signatures[0]
      expect(sig.location).toBe('Attestto Platform')
    })

    it('extracts contactInfo', async () => {
      const bytes = await readFile(REFERENCE_PDF)
      const file = new File([bytes], 'pades-reference_digitally_signed.pdf')

      const result = await verifyPdf(file)

      const sig = result.signatures[0]
      expect(sig.contactInfo).toBe('https://attestto.com/verify')
    })

    it('does NOT confuse /Filter /Name with signer /Name', async () => {
      const bytes = await readFile(REFERENCE_PDF)
      const file = new File([bytes], 'pades-reference_digitally_signed.pdf')

      const result = await verifyPdf(file)

      const sig = result.signatures[0]
      // Should be the signer name, NOT "Adobe.PPKLite"
      expect(sig.name).not.toBe('Adobe.PPKLite')
      expect(sig.name).not.toContain('PPKLite')
    })

    it('extracts sign date', async () => {
      const bytes = await readFile(REFERENCE_PDF)
      const file = new File([bytes], 'pades-reference_digitally_signed.pdf')

      const result = await verifyPdf(file)

      const sig = result.signatures[0]
      // signDate should be a parseable date string or null
      // Our reference PDF should have an /M entry
      if (sig.signDate) {
        expect(sig.signDate).toMatch(/^\d{4}/)
      }
    })
  })

  describe('non-signed PDF', () => {
    it('reports zero signatures for an unsigned PDF', async () => {
      // Create a minimal valid PDF
      const pdfContent = `%PDF-1.4
1 0 obj<</Type/Catalog/Pages 2 0 R>>endobj
2 0 obj<</Type/Pages/Kids[3 0 R]/Count 1>>endobj
3 0 obj<</Type/Page/MediaBox[0 0 612 792]/Parent 2 0 R>>endobj
xref
0 4
0000000000 65535 f
0000000009 00000 n
0000000058 00000 n
0000000115 00000 n
trailer<</Size 4/Root 1 0 R>>
startxref
190
%%EOF`
      const file = new File([pdfContent], 'unsigned.pdf')
      const result = await verifyPdf(file)

      expect(result.isPdf).toBe(true)
      expect(result.signatures).toHaveLength(0)
    })
  })

  describe('non-PDF file', () => {
    it('returns hash but no signatures for non-PDF', async () => {
      const file = new File(['hello world'], 'readme.txt')
      const result = await verifyPdf(file)

      expect(result.isPdf).toBe(false)
      expect(result.hash).toBeTruthy()
      expect(result.signatures).toHaveLength(0)
      expect(result.metadata).toBeNull()
    })
  })
})
